template <typename T>
__device__ __forceinline__ T tadd(T a, T b) { return a + b; }
template <typename T>
__device__ __forceinline__ T tmul(T a, T b) { return a * b; }
template <typename T>
__device__ __forceinline__ T tzero();
template <typename T>
__device__ __forceinline__ T tnegone();
template <typename T>
__device__ __forceinline__ bool teq(T a, T b) { return a == b; }

template <>
__device__ __forceinline__ float tzero<float>() { return 0.0f; }
template <>
__device__ __forceinline__ double tzero<double>() { return 0.0; }
template <>
__device__ __forceinline__ int tzero<int>() { return 0; }
template <>
__device__ __forceinline__ __half2 tzero<__half2>() { return __float2half2_rn(0.0f); }

template <>
__device__ __forceinline__ float tnegone<float>() { return -1.0f; }
template <>
__device__ __forceinline__ double tnegone<double>() { return -1.0; }
template <>
__device__ __forceinline__ int tnegone<int>() { return -1; }
template <>
__device__ __forceinline__ __half2 tnegone<__half2>() { return __float2half2_rn(-1.0f); }

template <>
__device__ __forceinline__ __half2 tadd<__half2>(__half2 a, __half2 b) { return __hadd2(a, b); }
template <>
__device__ __forceinline__ __half2 tmul<__half2>(__half2 a, __half2 b) { return __hmul2(a, b); }
template <>
__device__ __forceinline__ bool teq<__half2>(__half2 a, __half2 b) {
    return (__half2float(__low2half(a)) == __half2float(__low2half(b))) &&
           (__half2float(__high2half(a)) == __half2float(__high2half(b)));
}

template <typename T, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_func(T seed, T* g_data) {
    const unsigned int blockSize = blockDim.x;
    const int idx = BLOCK_STRIDED
                        ? (int)(blockIdx.x * blockSize * ELEMENTS_PER_THREAD + threadIdx.x)
                        : (int)(blockIdx.x * blockSize + threadIdx.x);
    const int stride = BLOCK_STRIDED ? (int)blockSize : (int)(gridDim.x * blockSize);
    const int big_stride = (int)(gridDim.x * blockSize * ELEMENTS_PER_THREAD);

    T tmps[ELEMENTS_PER_THREAD];
#pragma unroll
    for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];
#pragma unroll
            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = tadd<T>(tmul<T>(tmps[j], tmps[j]), seed);
            }
        }

        T sum = tzero<T>();
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
            sum = tadd<T>(sum, tmul<T>(tmps[j], tmps[j + 1]));
        }

        if (teq<T>(sum, tnegone<T>())) {
            g_data[idx + k * big_stride] = sum;
        }
    }
}

template <int COMPUTE_ITERATIONS, bool BLOCK_STRIDED>
__global__ void warmup_kernel(short seed, short* g_data) {
    const unsigned int blockSize = blockDim.x;
    const int idx = BLOCK_STRIDED
                        ? (int)(blockIdx.x * blockSize + threadIdx.x)
                        : (int)(blockIdx.x * blockSize + threadIdx.x);
    const int stride = BLOCK_STRIDED ? (int)blockSize : (int)(gridDim.x * blockSize);

    short v = g_data[idx];
#pragma unroll
    for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        v = (short)(v * v + seed);
    }
    if (v == (short)-1) g_data[idx + stride * 0] = v;
}

template <typename T, bool BLOCK_STRIDED>
static void launch_kernel_ci(int ci, T seed, T* dptr, dim3 grid, dim3 block) {
#define LAUNCH_CASE(N) case N: benchmark_func<T, N, 8, 4, BLOCK_STRIDED><<<grid, block>>>(seed, dptr); break
    switch (ci) {
        LAUNCH_CASE(0);   LAUNCH_CASE(1);   LAUNCH_CASE(2);   LAUNCH_CASE(3);
        LAUNCH_CASE(4);   LAUNCH_CASE(5);   LAUNCH_CASE(6);   LAUNCH_CASE(7);
        LAUNCH_CASE(8);   LAUNCH_CASE(9);   LAUNCH_CASE(10);  LAUNCH_CASE(11);
        LAUNCH_CASE(12);  LAUNCH_CASE(13);  LAUNCH_CASE(14);  LAUNCH_CASE(15);
        LAUNCH_CASE(16);  LAUNCH_CASE(17);  LAUNCH_CASE(18);  LAUNCH_CASE(20);
        LAUNCH_CASE(22);  LAUNCH_CASE(24);  LAUNCH_CASE(28);  LAUNCH_CASE(32);
        LAUNCH_CASE(40);  LAUNCH_CASE(48);  LAUNCH_CASE(56);  LAUNCH_CASE(64);
        LAUNCH_CASE(80);  LAUNCH_CASE(96);  LAUNCH_CASE(128); LAUNCH_CASE(192);
        LAUNCH_CASE(256);
        default: break;
    }
#undef LAUNCH_CASE
}

template <typename Launcher>
static double benchmark_ms(Launcher&& launch, bool use_os_timer) {
    constexpr int total_bench_iterations = 3;
    double acc = 0.0;

    for (int i = 0; i < total_bench_iterations; i++) {
        if (use_os_timer) {
            auto ts = std::chrono::high_resolution_clock::now();
            launch();
            CUDA_SAFE_CALL(cudaDeviceSynchronize());
            auto te = std::chrono::high_resolution_clock::now();
            std::chrono::duration<double, std::milli> ms = te - ts;
            acc += ms.count();
        } else {
            cudaEvent_t ev_start, ev_stop;
            CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
            CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
            CUDA_SAFE_CALL(cudaEventRecord(ev_start));
            launch();
            CUDA_SAFE_CALL(cudaEventRecord(ev_stop));
            CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
            float ms = 0.0f;
            CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
            acc += (double)ms;
            CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
            CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
        }
    }
    return acc / total_bench_iterations;
}

static void runbench_warmup(void* cbuffer, long size, size_t workgroupsize, bool block_strided) {
    const long reduced_grid_size = size / 256;
    dim3 block((unsigned)workgroupsize);
    dim3 grid((unsigned)(reduced_grid_size / (long)workgroupsize));
    short seed = 1;
    if (block_strided) {
        warmup_kernel<0, true><<<grid, block>>>(seed, (short*)cbuffer);
    } else {
        warmup_kernel<0, false><<<grid, block>>>(seed, (short*)cbuffer);
    }
    CUDA_SAFE_CALL(cudaGetLastError());
}

static void runbench(const int compute_iterations_arr[],
                     unsigned int krn_idx,
                     void* cbuffer,
                     long size,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool use_os_timer,
                     bool block_strided,
                     bool enable_dp,
                     bool enable_hp) {
    const long compute_grid_size = size / elements_per_wi / fusion_degree;
    const int current_compute_iterations = compute_iterations_arr[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2LL * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    dim3 block((unsigned)workgroupsize);
    dim3 grid((unsigned)(compute_grid_size / (long)workgroupsize));

    double kernel_time_mad_sp = benchmark_ms([&]() {
        float seed = 1.0f;
        if (block_strided) launch_kernel_ci<float, true>(current_compute_iterations, seed, (float*)cbuffer, grid, block);
        else launch_kernel_ci<float, false>(current_compute_iterations, seed, (float*)cbuffer, grid, block);
        CUDA_SAFE_CALL(cudaGetLastError());
    }, use_os_timer);

    double kernel_time_mad_dp = benchmark_ms([&]() {
        if (!enable_dp) return;
        double seed = 1.0;
        if (block_strided) launch_kernel_ci<double, true>(current_compute_iterations, seed, (double*)cbuffer, grid, block);
        else launch_kernel_ci<double, false>(current_compute_iterations, seed, (double*)cbuffer, grid, block);
        CUDA_SAFE_CALL(cudaGetLastError());
    }, use_os_timer);

    if (!enable_dp) kernel_time_mad_dp = 0.0;

    double kernel_time_mad_hp = benchmark_ms([&]() {
        if (!enable_hp) return;
        __half2 seed = __halves2half2(__float2half(1.0f), __float2half(1.0f));
        if (block_strided) launch_kernel_ci<__half2, true>(current_compute_iterations, seed, (__half2*)cbuffer, grid, block);
        else launch_kernel_ci<__half2, false>(current_compute_iterations, seed, (__half2*)cbuffer, grid, block);
        CUDA_SAFE_CALL(cudaGetLastError());
    }, use_os_timer);

    if (!enable_hp) kernel_time_mad_hp = 0.0;

    double kernel_time_mad_int = benchmark_ms([&]() {
        int seed = 1;
        if (block_strided) launch_kernel_ci<int, true>(current_compute_iterations, seed, (int*)cbuffer, grid, block);
        else launch_kernel_ci<int, false>(current_compute_iterations, seed, (int*)cbuffer, grid, block);
        CUDA_SAFE_CALL(cudaGetLastError());
    }, use_os_timer);

    printf(
        "         %4d,   %8.3f,%8.2f,%8.2f,%7.2f,   %8.3f,%8.2f,%8.2f,%7.2f,   "
        "%8.3f,%8.2f,%8.2f,%7.2f,  %8.3f,%8.2f,%8.2f,%7.2f\n",
        current_compute_iterations,
        ((double)computations) / ((double)memoryoperations * sizeof(float)),
        kernel_time_mad_sp,
        ((double)computations) / kernel_time_mad_sp * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(float)) / kernel_time_mad_sp * 1000. /
            (1000. * 1000. * 1000.),
        ((double)computations) / ((double)memoryoperations * sizeof(double)),
        kernel_time_mad_dp > 0.0 ? ((double)kernel_time_mad_dp) : 0.0,
        kernel_time_mad_dp > 0.0 ? (((double)computations) / kernel_time_mad_dp * 1000. /
            (double)(1000 * 1000 * 1000)) : 0.0,
        kernel_time_mad_dp > 0.0 ? (((double)memoryoperations * sizeof(double)) / kernel_time_mad_dp * 1000. /
            (1000. * 1000. * 1000.)) : 0.0,
        ((double)2 * computations) / ((double)memoryoperations * sizeof(__half2)),
        kernel_time_mad_hp > 0.0 ? ((double)kernel_time_mad_hp) : 0.0,
        kernel_time_mad_hp > 0.0 ? (((double)2 * computations) / kernel_time_mad_hp * 1000. /
            (double)(1000 * 1000 * 1000)) : 0.0,
        kernel_time_mad_hp > 0.0 ? (((double)memoryoperations * sizeof(__half2)) / kernel_time_mad_hp *
            1000. / (1000. * 1000. * 1000.)) : 0.0,
        ((double)computations) / ((double)memoryoperations * sizeof(int)),
        kernel_time_mad_int,
        ((double)computations) / kernel_time_mad_int * 1000. / (double)(1000 * 1000 * 1000),
        ((double)memoryoperations * sizeof(int)) / kernel_time_mad_int * 1000. /
            (1000. * 1000. * 1000.));
}

extern "C" void mixbenchGPU(double* c, long size) {
    const bool block_strided = false;
    const bool host_allocated = false;
    const bool use_os_timer = false;
    const size_t workgroupsize = 256;
    const unsigned int elements_per_wi = 8;
    const unsigned int fusion_degree = 4;

    const char* benchtype = block_strided ? "Workgroup" : "NDRange";
    printf("Workitem stride:        %s\n", benchtype);
    const char* buffer_allocation = host_allocated ? "Host allocated" : "Device allocated";
    printf("Buffer allocation:      %s\n", buffer_allocation);
    printf("Timer:                  %s\n", use_os_timer ? "OS based" : "CL event based");

    cudaDeviceProp prop = GetDeviceProperties();
    bool enable_dp = (prop.major > 1) || (prop.major == 1 && prop.minor >= 3);
    if (!enable_dp) {
        printf("Warning:                Double precision computations are not supported\n");
    }
    bool enable_hp = IsFP16Supported();
    if (!enable_hp) {
        printf("Warning:                Half precision computations are not supported\n");
    }

    void* c_buffer = nullptr;
    CUDA_SAFE_CALL(cudaMalloc(&c_buffer, (size_t)size * sizeof(double)));

    CUDA_SAFE_CALL(cudaMemset(c_buffer, 0, (size_t)size * sizeof(int)));

    runbench_warmup(c_buffer, size, workgroupsize, block_strided);
    CUDA_SAFE_CALL(cudaDeviceSynchronize());

    printf(
        "----------------------------------------------------------------------------- CSV data "
        "-----------------------------------------------------------------------------"
        "-----\n");
    printf(
        "Experiment ID, Single Precision ops,,,,              Double precision "
        "ops,,,,              Half precision ops,,,,                Integer "
        "operations,,, \n");
    printf(
        "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, Flops/byte, "
        "ex.time,  GFLOPS, GB/sec, Flops/byte, ex.time,  GFLOPS, GB/sec, "
        "Iops/byte, ex.time,   GIOPS, GB/sec\n");

    for (int i = 0; i < compute_iterations_len; i++) {
        runbench(compute_iterations, i, c_buffer, size, workgroupsize,
                 elements_per_wi, fusion_degree, use_os_timer, block_strided, enable_dp, enable_hp);
    }

    printf(
        "------------------------------------------------------------------------------------------------"
        "--------------------------------------------------------------"
        "--------------------\n");

    CUDA_SAFE_CALL(cudaMemcpy(c, c_buffer, (size_t)size * sizeof(double), cudaMemcpyDeviceToHost));
    CUDA_SAFE_CALL(cudaFree(c_buffer));
}

