void flushed_printf(const char* format, ...) {
  va_list args;
  va_start(args, format);
  vprintf(format, args);
  va_end(args);
  fflush(stdout);
}

void show_progress_init(int length) {
  flushed_printf("[");
  for (int i = 0; i < length; i++) flushed_printf(" ");
  flushed_printf("]");
  for (int i = 0; i <= length; i++) flushed_printf("\b");
}
void show_progress_step(int domove, char newchar) {
  flushed_printf("%c", newchar);
  if (!domove) flushed_printf("\b");
}
void show_progress_done(void) { flushed_printf("\n"); }

template <typename T>
struct Ops {
  __device__ static inline T add(T a, T b) { return a + b; }
  __device__ static inline T mul(T a, T b) { return a * b; }
  __device__ static inline T zero() { return (T)0; }
  __device__ static inline T negone() { return (T)-1; }
  __device__ static inline bool equal(T a, T b) { return a == b; }
};

template <>
struct Ops<__half2> {
  __device__ static inline __half2 add(__half2 a, __half2 b) { return __hadd2(a, b); }
  __device__ static inline __half2 mul(__half2 a, __half2 b) { return __hmul2(a, b); }
  __device__ static inline __half2 zero() { return __float2half2_rn(0.0f); }
  __device__ static inline __half2 negone() { return __float2half2_rn(-1.0f); }
  __device__ static inline bool equal(__half2 a, __half2 b) {
    __half2_raw ra = reinterpret_cast<const __half2_raw&>(a);
    __half2_raw rb = reinterpret_cast<const __half2_raw&>(b);
    return ra.x == rb.x && ra.y == rb.y;
  }
};

template <typename T, int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED>
__global__ void benchmark_func(T seed, T* g_data) {
  const unsigned int blockSize = blockDim.x;
  const int gid = (int)blockIdx.x * (int)blockDim.x + (int)threadIdx.x;

  const int stride = BLOCK_STRIDED ? (int)blockSize : (int)(blockDim.x * gridDim.x);
  const int idx = BLOCK_STRIDED
                      ? (int)blockIdx.x * (int)blockSize * ELEMENTS_PER_THREAD + (int)threadIdx.x
                      : gid;
  const int big_stride = (int)gridDim.x * (int)blockSize * ELEMENTS_PER_THREAD;

  T tmps[ELEMENTS_PER_THREAD];
#pragma unroll
  for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
      tmps[j] = g_data[idx + j * stride + k * big_stride];
#pragma unroll
      for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
        tmps[j] = Ops<T>::add(Ops<T>::mul(tmps[j], tmps[j]), seed);
      }
    }

    T sum = Ops<T>::zero();
#pragma unroll
    for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
      sum = Ops<T>::add(sum, Ops<T>::mul(tmps[j], tmps[j + 1]));
    }

    if (Ops<T>::equal(sum, Ops<T>::negone())) {
      g_data[idx + k * big_stride] = sum;
    }
  }
}

template <typename T, int EPW, int FD, bool BS, int CI>
static inline void launch_ci_kernel(T seed, T* ptr, long size, size_t wg) {
  const long compute_grid_size = size / EPW / FD;
  dim3 block((unsigned)wg);
  dim3 grid((unsigned)(compute_grid_size / (long)wg));
  benchmark_func<T, CI, EPW, FD, BS><<<grid, block>>>(seed, ptr);
}

#define CI_SWITCH(LAUNCH) \
  switch (ci) { \
    case 0: LAUNCH(0); break; case 1: LAUNCH(1); break; case 2: LAUNCH(2); break; case 3: LAUNCH(3); break; \
    case 4: LAUNCH(4); break; case 5: LAUNCH(5); break; case 6: LAUNCH(6); break; case 7: LAUNCH(7); break; \
    case 8: LAUNCH(8); break; case 9: LAUNCH(9); break; case 10: LAUNCH(10); break; case 11: LAUNCH(11); break; \
    case 12: LAUNCH(12); break; case 13: LAUNCH(13); break; case 14: LAUNCH(14); break; case 15: LAUNCH(15); break; \
    case 16: LAUNCH(16); break; case 17: LAUNCH(17); break; case 18: LAUNCH(18); break; case 20: LAUNCH(20); break; \
    case 22: LAUNCH(22); break; case 24: LAUNCH(24); break; case 28: LAUNCH(28); break; case 32: LAUNCH(32); break; \
    case 40: LAUNCH(40); break; case 48: LAUNCH(48); break; case 56: LAUNCH(56); break; case 64: LAUNCH(64); break; \
    case 80: LAUNCH(80); break; case 96: LAUNCH(96); break; case 128: LAUNCH(128); break; case 192: LAUNCH(192); break; \
    case 256: LAUNCH(256); break; default: break; \
  }

template <typename T, int EPW, int FD, bool BS>
static inline void launch_by_ci(int ci, T seed, T* ptr, long size, size_t wg) {
#define DO_LAUNCH(CI) launch_ci_kernel<T, EPW, FD, BS, CI>(seed, ptr, size, wg)
  CI_SWITCH(DO_LAUNCH);
#undef DO_LAUNCH
}

template <typename F>
double benchmark3(F&& fn) {
  double sum = 0.0;
  for (int i = 0; i < 3; i++) sum += fn();
  return sum / 3.0;
}

template <typename T, int EPW, int FD, bool BS>
double time_kernel(int ci, T seed, T* ptr, long size, size_t wg) {
  return benchmark3([&]() {
    cudaEvent_t ev_start, ev_stop;
    CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
    CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
    CUDA_SAFE_CALL(cudaEventRecord(ev_start, 0));
    launch_by_ci<T, EPW, FD, BS>(ci, seed, ptr, size, wg);
    CUDA_SAFE_CALL(cudaEventRecord(ev_stop, 0));
    CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
    float ms = 0.0f;
    CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
    CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
    CUDA_SAFE_CALL(cudaGetLastError());
    return (double)ms;
  });
}

