template <typename T>
__device__ __forceinline__ T zero_val();
template <>
__device__ __forceinline__ float zero_val<float>() { return 0.0f; }
template <>
__device__ __forceinline__ double zero_val<double>() { return 0.0; }
template <>
__device__ __forceinline__ int zero_val<int>() { return 0; }
template <>
__device__ __forceinline__ short zero_val<short>() { return 0; }
template <>
__device__ __forceinline__ __half2 zero_val<__half2>() { return __float2half2_rn(0.0f); }

template <typename T>
__device__ __forceinline__ T neg_one_val();
template <>
__device__ __forceinline__ float neg_one_val<float>() { return -1.0f; }
template <>
__device__ __forceinline__ double neg_one_val<double>() { return -1.0; }
template <>
__device__ __forceinline__ int neg_one_val<int>() { return -1; }
template <>
__device__ __forceinline__ short neg_one_val<short>() { return (short)-1; }
template <>
__device__ __forceinline__ __half2 neg_one_val<__half2>() { return __float2half2_rn(-1.0f); }

template <typename T>
__device__ __forceinline__ T mul_val(T a, T b) { return a * b; }
template <>
__device__ __forceinline__ __half2 mul_val<__half2>(__half2 a, __half2 b) { return __hmul2(a, b); }

template <typename T>
__device__ __forceinline__ T add_val(T a, T b) { return a + b; }
template <>
__device__ __forceinline__ __half2 add_val<__half2>(__half2 a, __half2 b) { return __hadd2(a, b); }

template <typename T>
__device__ __forceinline__ bool is_equal_val(T a, T b) { return a == b; }
template <>
__device__ __forceinline__ bool is_equal_val<__half2>(__half2 a, __half2 b) {
    return (__half_as_ushort(__low2half(a)) == __half_as_ushort(__low2half(b))) &&
           (__half_as_ushort(__high2half(a)) == __half_as_ushort(__high2half(b)));
}

template <int COMPUTE_ITERATIONS, int ELEMENTS_PER_THREAD, int FUSION_DEGREE, bool BLOCK_STRIDED, typename T>
__global__ void benchmark_func(T seed, T* g_data) {
    const unsigned int blockSize = blockDim.x;

    const int idx = BLOCK_STRIDED
                        ? (int)(blockIdx.x * blockSize * ELEMENTS_PER_THREAD + threadIdx.x)
                        : (int)(blockIdx.x * blockSize + threadIdx.x);

    const int stride = BLOCK_STRIDED ? (int)blockSize : (int)(blockSize * gridDim.x);
    const int big_stride = (int)(gridDim.x * blockSize * ELEMENTS_PER_THREAD);

    T tmps[ELEMENTS_PER_THREAD];
#pragma unroll
    for (int k = 0; k < FUSION_DEGREE; k++) {
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];
#pragma unroll
            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = add_val(mul_val(tmps[j], tmps[j]), seed);
            }
        }

        T sum = zero_val<T>();
#pragma unroll
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
            sum = add_val(sum, mul_val(tmps[j], tmps[j + 1]));
        }

        if (is_equal_val(sum, neg_one_val<T>())) {
            g_data[idx + k * big_stride] = sum;
        }
    }
}

#define ITER_LIST(M) \
    M(0) M(1) M(2) M(3) M(4) M(5) M(6) M(7) M(8) M(9) M(10) M(11) M(12) M(13) M(14) M(15) M(16) \
    M(17) M(18) M(20) M(22) M(24) M(28) M(32) M(40) M(48) M(56) M(64) M(80) M(96) M(128) M(192) M(256)

template <typename T, int EPT, int FD, bool BLOCK_STRIDED>
static void launch_bench_kernel(int iters, T seed, T* ptr, dim3 grid, dim3 block) {
    switch (iters) {
#define LAUNCH_CASE(I) case I: benchmark_func<I, EPT, FD, BLOCK_STRIDED, T><<<grid, block>>>(seed, ptr); break;
        ITER_LIST(LAUNCH_CASE)
#undef LAUNCH_CASE
        default: break;
    }
}

template <typename LaunchFn>
static double time_kernel_ms(LaunchFn&& fn) {
    constexpr int total_bench_iterations = 3;
    double total = 0.0;
    for (int i = 0; i < total_bench_iterations; i++) {
        cudaEvent_t ev_start, ev_stop;
        CUDA_SAFE_CALL(cudaEventCreate(&ev_start));
        CUDA_SAFE_CALL(cudaEventCreate(&ev_stop));
        CUDA_SAFE_CALL(cudaEventRecord(ev_start));
        fn();
        CUDA_SAFE_CALL(cudaEventRecord(ev_stop));
        CUDA_SAFE_CALL(cudaEventSynchronize(ev_stop));
        float ms = 0.0f;
        CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, ev_start, ev_stop));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_start));
        CUDA_SAFE_CALL(cudaEventDestroy(ev_stop));
        CUDA_SAFE_CALL(cudaGetLastError());
        total += (double)ms;
    }
    return total / (double)total_bench_iterations;
}

static void runbench_warmup(short* d_ptr, long size, size_t workgroupsize) {
    const long reduced_grid_size = size / 256;
    dim3 block((unsigned int)workgroupsize);
    dim3 grid((unsigned int)(reduced_grid_size / (long)workgroupsize));
    const short seed = 1;
    launch_bench_kernel<short, 1, 1, false>(0, seed, d_ptr, grid, block);
    CUDA_SAFE_CALL(cudaDeviceSynchronize());
}

static void runbench(const int compute_iterations[],
                     unsigned int krn_idx,
                     double* d_buffer,
                     long size,
                     size_t workgroupsize,
                     unsigned int elements_per_wi,
                     unsigned int fusion_degree,
                     bool enable_dp,
                     bool enable_hp) {
    const long compute_grid_size = size / (long)elements_per_wi / (long)fusion_degree;
    const int current_compute_iterations = compute_iterations[krn_idx];
    const long long computations =
        (elements_per_wi * (long long)compute_grid_size +
         (2 * elements_per_wi * current_compute_iterations) * (long long)compute_grid_size) *
        fusion_degree;
    const long long memoryoperations = size;

    dim3 block((unsigned int)workgroupsize);
    dim3 grid((unsigned int)(compute_grid_size / (long)workgroupsize));

    double kernel_time_mad_sp = time_kernel_ms([&]() {
        float* ptr = reinterpret_cast<float*>(d_buffer);
        const float seed_f = 1.0f;
        launch_bench_kernel<float, 8, 4, false>(current_compute_iterations, seed_f, ptr, grid, block);
    });

    double kernel_time_mad_dp = 0.0;
    if (enable_dp) {
        kernel_time_mad_dp = time_kernel_ms([&]() {
            double* ptr = reinterpret_cast<double*>(d_buffer);
            const double seed_d = 1.0;
            launch_bench_kernel<double, 8, 4, false>(current_compute_iterations, seed_d, ptr, grid, block);
        });
    }

