	momentum_i.y = variables[i + (VAR_MOMENTUM+1)*nelr];
	momentum_i.z = variables[i + (VAR_MOMENTUM+2)*nelr];

	float density_energy_i = variables[i + VAR_DENSITY_ENERGY*nelr];

	float3 velocity_i; compute_velocity(density_i, momentum_i, &velocity_i);
	float speed_sqd_i = compute_speed_sqd(velocity_i);
	float speed_i = sqrtf(speed_sqd_i);
	float pressure_i = compute_pressure(density_i, density_energy_i, speed_sqd_i);
	float speed_of_sound_i = compute_speed_of_sound(density_i, pressure_i);
	float3 flux_contribution_i_momentum_x, flux_contribution_i_momentum_y, flux_contribution_i_momentum_z;
	float3 flux_contribution_i_density_energy;
	compute_flux_contribution(density_i, momentum_i, density_energy_i, pressure_i, velocity_i,
	                          flux_contribution_i_momentum_x, flux_contribution_i_momentum_y,
	                          flux_contribution_i_momentum_z, flux_contribution_i_density_energy);

	float flux_i_density = float(0.0f);
	float3 flux_i_momentum;
	flux_i_momentum.x = float(0.0f);
	flux_i_momentum.y = float(0.0f);
	flux_i_momentum.z = float(0.0f);
	float flux_i_density_energy = float(0.0f);

	float3 velocity_nb;
	float density_nb, density_energy_nb;
	float3 momentum_nb;
	float3 flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y, flux_contribution_nb_momentum_z;
	float3 flux_contribution_nb_density_energy;
	float speed_sqd_nb, speed_of_sound_nb, pressure_nb;

	#pragma unroll
	for(j = 0; j < NNB; j++){
		nb = elements_surrounding_elements[i + j*nelr];
		normal.x = normals[i + (j + 0*NNB)*nelr];
		normal.y = normals[i + (j + 1*NNB)*nelr];
		normal.z = normals[i + (j + 2*NNB)*nelr];

		normal_len = sqrtf(normal.x*normal.x + normal.y*normal.y + normal.z*normal.z);

		if(nb >= 0){
			density_nb = variables[nb + VAR_DENSITY*nelr];
			momentum_nb.x = variables[nb + (VAR_MOMENTUM+0)*nelr];
			momentum_nb.y = variables[nb + (VAR_MOMENTUM+1)*nelr];
			momentum_nb.z = variables[nb + (VAR_MOMENTUM+2)*nelr];
			density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];
			compute_velocity(density_nb, momentum_nb, &velocity_nb);
			speed_sqd_nb = compute_speed_sqd(velocity_nb);
			pressure_nb = compute_pressure(density_nb, density_energy_nb, speed_sqd_nb);
			speed_of_sound_nb = compute_speed_of_sound(density_nb, pressure_nb);
			compute_flux_contribution(density_nb, momentum_nb, density_energy_nb, pressure_nb, velocity_nb,
			                          flux_contribution_nb_momentum_x, flux_contribution_nb_momentum_y,
			                          flux_contribution_nb_momentum_z, flux_contribution_nb_density_energy);

			factor = -normal_len*smoothing_coefficient*float(0.5f)*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
			flux_i_density += factor*(density_i-density_nb);
			flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
			flux_i_momentum.x += factor*(momentum_i.x-momentum_nb.x);
			flux_i_momentum.y += factor*(momentum_i.y-momentum_nb.y);
			flux_i_momentum.z += factor*(momentum_i.z-momentum_nb.z);

			factor = float(0.5f)*normal.x;
			flux_i_density += factor*(momentum_nb.x+momentum_i.x);
			flux_i_density_energy += factor*(flux_contribution_nb_density_energy.x+flux_contribution_i_density_energy.x);
			flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.x+flux_contribution_i_momentum_x.x);
			flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.x+flux_contribution_i_momentum_y.x);
			flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.x+flux_contribution_i_momentum_z.x);

			factor = float(0.5f)*normal.y;
			flux_i_density += factor*(momentum_nb.y+momentum_i.y);
			flux_i_density_energy += factor*(flux_contribution_nb_density_energy.y+flux_contribution_i_density_energy.y);
			flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.y+flux_contribution_i_momentum_x.y);
			flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.y+flux_contribution_i_momentum_y.y);
			flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.y+flux_contribution_i_momentum_z.y);

			factor = float(0.5f)*normal.z;
			flux_i_density += factor*(momentum_nb.z+momentum_i.z);
			flux_i_density_energy += factor*(flux_contribution_nb_density_energy.z+flux_contribution_i_density_energy.z);
			flux_i_momentum.x += factor*(flux_contribution_nb_momentum_x.z+flux_contribution_i_momentum_x.z);
			flux_i_momentum.y += factor*(flux_contribution_nb_momentum_y.z+flux_contribution_i_momentum_y.z);
			flux_i_momentum.z += factor*(flux_contribution_nb_momentum_z.z+flux_contribution_i_momentum_z.z);
		}
		else if(nb == -1){
			flux_i_momentum.x += normal.x*pressure_i;
			flux_i_momentum.y += normal.y*pressure_i;
			flux_i_momentum.z += normal.z*pressure_i;
		}
		else if(nb == -2){
			factor = float(0.5f)*normal.x;
			flux_i_density += factor*(c_ff_variable[VAR_MOMENTUM+0]+momentum_i.x);
			flux_i_density_energy += factor*(c_ff_flux_contribution_density_energy[0].x+flux_contribution_i_density_energy.x);
			flux_i_momentum.x += factor*(c_ff_flux_contribution_momentum_x[0].x + flux_contribution_i_momentum_x.x);
			flux_i_momentum.y += factor*(c_ff_flux_contribution_momentum_y[0].x + flux_contribution_i_momentum_y.x);
			flux_i_momentum.z += factor*(c_ff_flux_contribution_momentum_z[0].x + flux_contribution_i_momentum_z.x);

			factor = float(0.5f)*normal.y;
			flux_i_density += factor*(c_ff_variable[VAR_MOMENTUM+1]+momentum_i.y);
			flux_i_density_energy += factor*(c_ff_flux_contribution_density_energy[0].y+flux_contribution_i_density_energy.y);
			flux_i_momentum.x += factor*(c_ff_flux_contribution_momentum_x[0].y + flux_contribution_i_momentum_x.y);
			flux_i_momentum.y += factor*(c_ff_flux_contribution_momentum_y[0].y + flux_contribution_i_momentum_y.y);
			flux_i_momentum.z += factor*(c_ff_flux_contribution_momentum_z[0].y + flux_contribution_i_momentum_z.y);

			factor = float(0.5f)*normal.z;
			flux_i_density += factor*(c_ff_variable[VAR_MOMENTUM+2]+momentum_i.z);
			flux_i_density_energy += factor*(c_ff_flux_contribution_density_energy[0].z+flux_contribution_i_density_energy.z);
			flux_i_momentum.x += factor*(c_ff_flux_contribution_momentum_x[0].z + flux_contribution_i_momentum_x.z);
			flux_i_momentum.y += factor*(c_ff_flux_contribution_momentum_y[0].z + flux_contribution_i_momentum_y.z);
			flux_i_momentum.z += factor*(c_ff_flux_contribution_momentum_z[0].z + flux_contribution_i_momentum_z.z);
		}
	}

	fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
	fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum.x;
	fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum.y;
	fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum.z;
	fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
}

__global__ void time_step_kernel(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes){
	const int i = blockDim.x * blockIdx.x + threadIdx.x;
	if(i >= nelr) return;

	float factor = step_factors[i]/float(RK+1-j);

	variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
	variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
	variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
	variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];
	variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];
}

void initialize_variables(int nelr, float* variables, float*){
	int block = BLOCK_SIZE_1;
	int grid = (nelr + block - 1) / block;
	initialize_variables_kernel<<<grid, block>>>(variables, nelr);
}

void compute_step_factor(int nelr, float* variables, float* areas, float* step_factors){
	int block = BLOCK_SIZE_2;
	int grid = (nelr + block - 1) / block;
	compute_step_factor_kernel<<<grid, block>>>(variables, areas, step_factors, nelr);
}

void compute_flux(int nelr, int* elements_surrounding_elements, float* normals, float* variables, float*,
                  float* fluxes, float3*, float3*, float3*, float3*){
	int block = BLOCK_SIZE_3;
	int grid = (nelr + block - 1) / block;
	compute_flux_kernel<<<grid, block>>>(elements_surrounding_elements, normals, variables, fluxes, nelr);
}

void time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes){
	int block = BLOCK_SIZE_4;
	int grid = (nelr + block - 1) / block;
	time_step_kernel<<<grid, block>>>(j, nelr, old_variables, variables, step_factors, fluxes);
}

string device_type = "";
int device_id = 0;
int platform_id = 0;

void _clCmdParams(int argc, char* argv[]){
	for (int i = 0; i < argc; ++i){
		if(argv[i][0] != '-') continue;
		switch (argv[i][1]){
			case 't':
				if (++i < argc) device_type = argv[i];
				else throw string("Could not read argument after option -t");
				break;
			case 'd':
				if (++i < argc) device_id = atoi(argv[i]);
				else throw string("Could not read argument after option -d");
				break;
			case 'p':
				if (++i < argc) platform_id = atoi(argv[i]);
				else throw string("Could not read argument after option -p");
				break;
			default:
				break;
		}
	}
}

int main(int argc, char** argv){
	printf("WG size of kernel:initialize = %d, WG size of kernel:compute_step_factor = %d, WG size of kernel:compute_flux = %d, WG size of kernel:time_step = %d\n",
	       BLOCK_SIZE_1, BLOCK_SIZE_2, BLOCK_SIZE_3, BLOCK_SIZE_4);

	if (argc < 2){
		std::cout << "specify data file name and [device type] [device id]" << std::endl;
		return 0;
	}
	const char* data_file_name = argv[1];

	float* ff_variable = nullptr;
	float3* ff_flux_contribution_momentum_x = nullptr;
	float3* ff_flux_contribution_momentum_y = nullptr;
	float3* ff_flux_contribution_momentum_z = nullptr;
	float3* ff_flux_contribution_density_energy = nullptr;
	float* areas = nullptr;
	int* elements_surrounding_elements = nullptr;
	float* normals = nullptr;
	float* variables = nullptr;
	float* old_variables = nullptr;
	float* fluxes = nullptr;
	float* step_factors = nullptr;
	float h_ff_variable[NVAR];

	try{
		_clCmdParams(argc, argv);

		int device_count = 0;
		checkCudaErrors(cudaGetDeviceCount(&device_count));
		if(device_count <= 0) throw string("No CUDA devices found");
		if(device_id < 0 || device_id >= device_count) device_id = 0;
		checkCudaErrors(cudaSetDevice(device_id));

		{
			const float angle_of_attack = float(3.1415926535897931 / 180.0f) * float(deg_angle_of_attack);

			h_ff_variable[VAR_DENSITY] = float(1.4f);

			float ff_pressure = float(1.0f);
			float ff_speed_of_sound = sqrtf(GAMMA*ff_pressure / h_ff_variable[VAR_DENSITY]);
			float ff_speed = float(ff_mach)*ff_speed_of_sound;

			float3 ff_velocity;
			ff_velocity.x = ff_speed*float(cos((float)angle_of_attack));
			ff_velocity.y = ff_speed*float(sin((float)angle_of_attack));
			ff_velocity.z = 0.0f;

			h_ff_variable[VAR_MOMENTUM+0] = h_ff_variable[VAR_DENSITY] * ff_velocity.x;
			h_ff_variable[VAR_MOMENTUM+1] = h_ff_variable[VAR_DENSITY] * ff_velocity.y;
			h_ff_variable[VAR_MOMENTUM+2] = h_ff_variable[VAR_DENSITY] * ff_velocity.z;

			h_ff_variable[VAR_DENSITY_ENERGY] = h_ff_variable[VAR_DENSITY]*(float(0.5f)*(ff_speed*ff_speed)) + (ff_pressure / float(GAMMA-1.0f));

			float3 h_ff_momentum;
			h_ff_momentum.x = *(h_ff_variable+VAR_MOMENTUM+0);
			h_ff_momentum.y = *(h_ff_variable+VAR_MOMENTUM+1);
			h_ff_momentum.z = *(h_ff_variable+VAR_MOMENTUM+2);
			float3 h_ff_flux_contribution_momentum_x;
			float3 h_ff_flux_contribution_momentum_y;
			float3 h_ff_flux_contribution_momentum_z;
			float3 h_ff_flux_contribution_density_energy;
			compute_flux_contribution(h_ff_variable[VAR_DENSITY], h_ff_momentum, h_ff_variable[VAR_DENSITY_ENERGY], ff_pressure, ff_velocity,
			                          h_ff_flux_contribution_momentum_x, h_ff_flux_contribution_momentum_y,
			                          h_ff_flux_contribution_momentum_z, h_ff_flux_contribution_density_energy);

			checkCudaErrors(cudaMemcpyToSymbol(c_ff_variable, h_ff_variable, NVAR*sizeof(float)));
			checkCudaErrors(cudaMemcpyToSymbol(c_ff_flux_contribution_momentum_x, &h_ff_flux_contribution_momentum_x, sizeof(float3)));
			checkCudaErrors(cudaMemcpyToSymbol(c_ff_flux_contribution_momentum_y, &h_ff_flux_contribution_momentum_y, sizeof(float3)));
			checkCudaErrors(cudaMemcpyToSymbol(c_ff_flux_contribution_momentum_z, &h_ff_flux_contribution_momentum_z, sizeof(float3)));
			checkCudaErrors(cudaMemcpyToSymbol(c_ff_flux_contribution_density_energy, &h_ff_flux_contribution_density_energy, sizeof(float3)));
			checkCudaErrors(cudaDeviceSynchronize());
		}

		int nel;
		int nelr;

		{
			std::ifstream file(data_file_name);
			if(!file) throw(string("can not find/open file!"));

			file >> nel;
			nelr = block_length*((nel / block_length )+ std::min(1, nel % block_length));
			std::cout<<"--cambine: nel="<<nel<<", nelr="<<nelr<<std::endl;

			float* h_areas = new float[nelr];
			int* h_elements_surrounding_elements = new int[nelr*NNB];
			float* h_normals = new float[nelr*NDIM*NNB];

			for(int i = 0; i < nel; i++){
				file >> h_areas[i];
				for(int j = 0; j < NNB; j++){
					file >> h_elements_surrounding_elements[i + j*nelr];
					if(h_elements_surrounding_elements[i+j*nelr] < 0) h_elements_surrounding_elements[i+j*nelr] = -1;
					h_elements_surrounding_elements[i + j*nelr]--;

					for(int k = 0; k < NDIM; k++){
						file >> h_normals[i + (j + k*NNB)*nelr];
						h_normals[i + (j + k*NNB)*nelr] = -h_normals[i + (j + k*NNB)*nelr];
					}
				}
			}

			int last = nel-1;
			for(int i = nel; i < nelr; i++){
				h_areas[i] = h_areas[last];
				for(int j = 0; j < NNB; j++){
					h_elements_surrounding_elements[i + j*nelr] = h_elements_surrounding_elements[last + j*nelr];
					for(int k = 0; k < NDIM; k++) h_normals[last + (j + k*NNB)*nelr] = h_normals[last + (j + k*NNB)*nelr];
				}
			}

			areas = alloc<float>(nelr);
			upload<float>(areas, h_areas, nelr);

			elements_surrounding_elements = alloc<int>(nelr*NNB);
			upload<int>(elements_surrounding_elements, h_elements_surrounding_elements, nelr*NNB);

			normals = alloc<float>(nelr*NDIM*NNB);
			upload<float>(normals, h_normals, nelr*NDIM*NNB);

			delete[] h_areas;
			delete[] h_elements_surrounding_elements;
			delete[] h_normals;
		}

		variables = alloc<float>(nelr*NVAR);
		initialize_variables(nelr, variables, ff_variable);
		old_variables = alloc<float>(nelr*NVAR);
		fluxes = alloc<float>(nelr*NVAR);
		step_factors = alloc<float>(nelr);

		initialize_variables(nelr, old_variables, ff_variable);
		initialize_variables(nelr, fluxes, ff_variable);
		checkCudaErrors(cudaMemset(step_factors, 0, sizeof(float)*nelr));

		checkCudaErrors(cudaDeviceSynchronize());

		std::cout << "Starting..." << std::endl;

		for(int i = 0; i < iterations; i++){
			copy<float>(old_variables, variables, nelr*NVAR);

			compute_step_factor(nelr, variables, areas, step_factors);
			for(int j = 0; j < RK; j++){
				compute_flux(nelr, elements_surrounding_elements, normals, variables, ff_variable, fluxes,
				             ff_flux_contribution_density_energy, ff_flux_contribution_momentum_x,
				             ff_flux_contribution_momentum_y, ff_flux_contribution_momentum_z);

				time_step(j, nelr, old_variables, variables, step_factors, fluxes);
			}
		}
		checkCudaErrors(cudaDeviceSynchronize());

		std::cout << "Saving solution..." << std::endl;
		dump(variables, nel, nelr);
		std::cout << "Saved solution..." << std::endl;

		std::cout << "Cleaning up..." << std::endl;
		dealloc<float>(ff_variable);
		dealloc<float3>(ff_flux_contribution_momentum_x);
		dealloc<float3>(ff_flux_contribution_momentum_y);
		dealloc<float3>(ff_flux_contribution_momentum_z);
		dealloc<float3>(ff_flux_contribution_density_energy);
		dealloc<float>(areas);
		dealloc<int>(elements_surrounding_elements);
		dealloc<float>(normals);
		dealloc<float>(variables);
		dealloc<float>(old_variables);
		dealloc<float>(fluxes);
		dealloc<float>(step_factors);

		std::cout << "Done..." << std::endl;
	}
	catch(string msg){
		std::cout<<"--cambine:( an exception catched in main body ->"<<msg<<std::endl;
		dealloc<float>(ff_variable);
		dealloc<float3>(ff_flux_contribution_momentum_x);
		dealloc<float3>(ff_flux_contribution_momentum_y);
		dealloc<float3>(ff_flux_contribution_momentum_z);
		dealloc<float3>(ff_flux_contribution_density_energy);
		dealloc<float>(areas);
		dealloc<int>(elements_surrounding_elements);
		dealloc<float>(normals);
		dealloc<float>(variables);
		dealloc<float>(old_variables);
		dealloc<float>(fluxes);
		dealloc<float>(step_factors);
	}
	catch(...){
		std::cout<<"--cambine:( unknow exceptions in main body..."<<std::endl;
		dealloc<float>(ff_variable);
		dealloc<float3>(ff_flux_contribution_momentum_x);
		dealloc<float3>(ff_flux_contribution_momentum_y);
		dealloc<float3>(ff_flux_contribution_momentum_z);
		dealloc<float3>(ff_flux_contribution_density_energy);
		dealloc<float>(areas);
		dealloc<int>(elements_surrounding_elements);
		dealloc<float>(normals);
		dealloc<float>(variables);
		dealloc<float>(old_variables);
		dealloc<float>(fluxes);
		dealloc<float>(step_factors);
	}

	return 0;
}

#include <cuda_runtime.h>
