void run_event_based_simulation(Input input, SimulationData data, unsigned long * vhash_result)
{
	printf("Running event based simulation...\n");

	const int block_size = 256;
	const int grid_size = (input.lookups + block_size - 1) / block_size;

	xs_lookup_kernel_baseline<<<grid_size, block_size>>>(input, data);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	thrust::device_ptr<unsigned long> vptr = thrust::device_pointer_cast(data.verification);
	unsigned long vhash = thrust::reduce(thrust::device, vptr, vptr + input.lookups, (unsigned long)0, thrust::plus<unsigned long>());

