	x *= x; x *= x; x *= x; x *= x;
	return x;
}

__device__ RSComplex fast_cexp(RSComplex z)
{
	double x = z.r;
	double y = z.i;

	double t1 = fast_exp(x);
	double t2 = cos(y);
	double t3 = sin(y);

	RSComplex t4 = {t2, t3};
	RSComplex t5 = {t1, 0};
	return c_mul(t5, t4);
}

