		else if( 0 == strcmp(arg, "-W") )
		{
			if( ++i < argc )
				input.avg_n_windows = atoi(argv[i]);
			else
				print_CLI_error();
		}
		else if( 0 == strcmp(arg, "-p") )
		{
			if( ++i < argc )
				input.avg_n_poles = atoi(argv[i]);
			else
				print_CLI_error();
		}
		else if( 0 == strcmp(arg, "-k") )
		{
			if( ++i < argc )
				input.kernel_id = atoi(argv[i]);
			else
				print_CLI_error();
		}
		else if( 0 == strcmp(arg, "-P") )
