unsigned long long run_event_based_simulation_baseline(Inputs in, SimulationData GSD, int mype)
{
	if(mype == 0) printf("Running event based simulation...\n");

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;
	xs_lookup_kernel_baseline<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	if(mype == 0) printf("Reducing verification value...\n");
	thrust::device_ptr<unsigned long> vptr(GSD.verification);
	unsigned long sum = thrust::reduce(vptr, vptr + in.lookups, (unsigned long)0, thrust::plus<unsigned long>());

	return (unsigned long long)sum;
}

